#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std;bool check(vector<int>&a, int x){    vector<int>b;    for(int i=0;i<a.size();i++){        if(a[i]!=x){            b.push_back(a[i]);        }    }    int n= b.size();    for(int i=0;i<n;i++){        if(b[i]!= b[n-i-1]){            return false;        }    }    return true;}void solve(){    int n;        cin>>n;        vector<int>a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        for(int i=0;i<n;i++){            if(a[i]!=a[n - i - 1]){                if(check(a,a[i]) || check(a,a[n - i - 1])){                    cout<<"yes\n";                }                else{                    cout<<"no\n";                }                return;            }        }        cout<<"yes\n";}int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        solve();    }}